- `Snippet:s2sCopyBlobSnapshot` — insert after the `s2sCopyBlob` code block in the **Blob Copy** section
- `Snippet:s2sCopyBlobVersion` — insert after the `s2sCopyBlobSnapshot` block

**For `Azure.Storage.DataMovement.Files.Shares`:**

Create or extend a sample test file at:
`sdk/storage/Azure.Storage.DataMovement.Files.Shares/tests/Samples/Sample_ShareSnapshot.cs`

```csharp
// Copyright (c) Microsoft Corporation. All rights reserved.
// Licensed under the MIT License.

using System.Threading.Tasks;
using Azure.Core;
using Azure.Identity;
using Azure.Storage.DataMovement;
using Azure.Storage.DataMovement.Files.Shares;
using NUnit.Framework;

namespace Azure.Storage.DataMovement.Files.Shares.Tests.Samples
{
    public class Sample_ShareSnapshot : SamplesBase<DataMovementShareTestEnvironment>
    {
        [Test]
        [Ignore("Requires live resources")]
        public async Task CopyFileSnapshot()
        {
            System.Uri sourceFileUri = new System.Uri(TestEnvironment.StorageAccountShareUri);
            System.Uri destinationFileUri = new System.Uri(TestEnvironment.StorageAccountShareUri);
            TokenCredential tokenCredential = new DefaultAzureCredential();
            ShareFilesStorageResourceProvider shares = new(tokenCredential);
            TransferManager transferManager = new TransferManager(new TransferManagerOptions());

